/* =========================================================
   DATA FOTO MENU
   (baris panjang di bawah ini adalah data gambar — tidak perlu diedit)
   ========================================================= */
window.__MENU_IMGS__ = {"IMG1": "data:image/jpeg;base64,", "IMG2": "data:image/jpeg;base64,", "IMG3": "data:image/jpeg;base64,", "IMG4": "data:image/jpeg;base64,"};


/* =========================================================
   LOGIKA LOGIN
   ========================================================= */
// ====== LOGIKA LOGIN ======

  const pass = document.getElementById('password');
  const toggle = document.getElementById('togglePass');
  const eye = document.getElementById('eyeIcon');
  toggle.addEventListener('click', () => {
    const show = pass.type === 'password';
    pass.type = show ? 'text' : 'password';
    toggle.setAttribute('aria-label', show ? 'Sembunyikan kata sandi' : 'Tampilkan kata sandi');
    eye.innerHTML = show
      ? '<path d="M4 4l16 16" stroke="currentColor" stroke-width="1.6" stroke-linecap="round"/><path d="M9.5 5.7A9.6 9.6 0 0 1 12 5.5c6 0 9.5 6.5 9.5 6.5a17 17 0 0 1-2.8 3.5M6.2 7.4A17 17 0 0 0 2.5 12S6 18.5 12 18.5a9.4 9.4 0 0 0 3-.5" stroke="currentColor" stroke-width="1.6" stroke-linecap="round"/><path d="M9.9 9.9a3 3 0 0 0 4.2 4.2" stroke="currentColor" stroke-width="1.6"/>'
      : '<path d="M2.5 12S6 5.5 12 5.5 21.5 12 21.5 12 18 18.5 12 18.5 2.5 12 2.5 12Z" stroke="currentColor" stroke-width="1.6"/><circle cx="12" cy="12" r="3" stroke="currentColor" stroke-width="1.6"/>';
  });

  const form = document.getElementById('loginForm');
  const errBox = document.getElementById('errBox');
  const errText = document.getElementById('errText');
  const loginCard = document.querySelector('#loginScreen .card');

  const userInput = document.getElementById('username');
  function clearInvalid(){ userInput.classList.remove('invalid'); pass.classList.remove('invalid'); }
  function showError(msg){
    errText.textContent = msg;
    errBox.classList.remove('show'); void errBox.offsetWidth; errBox.classList.add('show');
    loginCard.classList.remove('shake'); void loginCard.offsetWidth; loginCard.classList.add('shake');
  }
  userInput.addEventListener('input', clearInvalid);
  pass.addEventListener('input', clearInvalid);

  // ===== Profil mengikuti username yang diketik saat login =====
  function showAccount(username){
    document.getElementById('accName').textContent = username;
    document.getElementById('accEmail').textContent = username + '@gmail.com';
    document.getElementById('accAvatar').textContent = (username[0] || 'A').toUpperCase();
  }

  // ===== LAYAR SUKSES LOGIN (mandiri, dibuat oleh JS) =====
  const SUCCESS_MS = 3000; // lama layar sukses tampil (ubah di sini, dalam milidetik)
  function ensureSuccessStyles(){
    if(document.getElementById('loginAnimCss')) return;
    const s = document.createElement('style');
    s.id = 'loginAnimCss';
    s.textContent = `
      #loginSuccessJS{position:fixed;inset:0;z-index:9999;display:none;align-items:center;justify-content:center;
        background:radial-gradient(circle at 50% 42%, #3a2216 0%, #2A1710 72%);opacity:0;transition:opacity .4s ease;
        font-family:'DM Sans',sans-serif}
      #loginSuccessJS.on{opacity:1}
      #loginSuccessJS .sbox{text-align:center;color:#FBF5ED;transform:scale(.88) translateY(8px);opacity:0;
        transition:transform .5s cubic-bezier(.2,.8,.2,1) .05s, opacity .5s .05s}
      #loginSuccessJS.on .sbox{transform:none;opacity:1}
      #loginSuccessJS .ring{width:112px;height:112px;border-radius:50%;margin:0 auto 22px;
        background:rgba(95,184,119,.16);display:flex;align-items:center;justify-content:center}
      #loginSuccessJS svg{width:112px;height:112px}
      #loginSuccessJS .c1{stroke:#5FB877;stroke-width:3;fill:none;stroke-dasharray:151;stroke-dashoffset:151;animation:jsDraw .6s ease .25s forwards}
      #loginSuccessJS .c2{stroke:#5FB877;stroke-width:4.5;fill:none;stroke-linecap:round;stroke-linejoin:round;stroke-dasharray:44;stroke-dashoffset:44;animation:jsDraw .45s ease .8s forwards}
      #loginSuccessJS h2{font-family:'Fraunces',serif;font-size:26px;font-weight:600;margin:0}
      #loginSuccessJS p{color:rgba(251,245,237,.72);font-size:15px;margin:7px 0 0}
      @keyframes jsDraw{to{stroke-dashoffset:0}}
    `;
    document.head.appendChild(s);
  }
  function showSuccessScreen(username, done){
    ensureSuccessStyles();
    let ov = document.getElementById('loginSuccessJS');
    if(!ov){
      ov = document.createElement('div');
      ov.id = 'loginSuccessJS';
      ov.innerHTML = `
        <div class="sbox">
          <div class="ring"><svg viewBox="0 0 52 52"><circle class="c1" cx="26" cy="26" r="24"/><path class="c2" d="M15 27l7 7 15-15"/></svg></div>
          <h2>Berhasil masuk</h2>
          <p id="jsSuccessSub"></p>
        </div>`;
      document.body.appendChild(ov);
    }
    ov.querySelector('#jsSuccessSub').textContent = 'Selamat datang, ' + username + ' 👋';
    ov.style.display = 'flex';
    // ulangi animasi gambar centang tiap kali tampil
    ov.querySelectorAll('.c1,.c2').forEach(el => { el.style.animation = 'none'; void el.offsetWidth; el.style.animation = ''; });
    requestAnimationFrame(() => ov.classList.add('on'));
    setTimeout(() => {
      ov.classList.remove('on');
      if(done) done();
      setTimeout(() => { ov.style.display = 'none'; }, 450);
    }, SUCCESS_MS);
  }

  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const u = userInput.value.trim();
    const p = pass.value.trim();
    clearInvalid();

    if (!u && !p){ userInput.classList.add('invalid'); pass.classList.add('invalid'); showError('Nama pengguna dan kata sandi wajib diisi.'); return; }
    if (!u){ userInput.classList.add('invalid'); showError('Nama pengguna wajib diisi.'); return; }
    if (!p){ pass.classList.add('invalid'); showError('Kata sandi wajib diisi.'); return; }
    if (u !== 'chandy'){ userInput.classList.add('invalid'); showError('Nama pengguna tidak ditemukan.'); return; }
    if (!(await verifyPassword(p))){ pass.classList.add('invalid'); showError('Kata sandi salah.'); return; }

    // ===== berhasil masuk =====
    errBox.classList.remove('show'); clearInvalid();
    showAccount(u);
    showSuccessScreen(u, () => {
      document.getElementById('loginScreen').style.display = 'none';
      const adminApp = document.getElementById('adminApp');
      adminApp.style.display = 'block';
      adminApp.classList.remove('fade-in'); void adminApp.offsetWidth; adminApp.classList.add('fade-in');
      window.scrollTo(0,0);
    });
  });


/* =========================================================
   LOGIKA DASBOR (menu, pesanan, unggah foto, dll)
   ========================================================= */
// ====== LOGIKA DASBOR ======

  const IMGS = window.__MENU_IMGS__;
  const rupiah = n => 'Rp ' + Number(n).toLocaleString('id-ID');

  // ============ NAVIGASI SIDEBAR ============
  const navItems = document.querySelectorAll('.nav-item[data-view]');
  function goView(name){
    document.querySelectorAll('.view').forEach(v => v.classList.remove('active'));
    document.getElementById('view-'+name).classList.add('active');
    navItems.forEach(n => n.classList.toggle('active', n.dataset.view === name));
    if(name==='laporan') renderReport();
    document.querySelector('.main').scrollTop = 0;
  }
  navItems.forEach(n => n.addEventListener('click', () => goView(n.dataset.view)));
  document.querySelectorAll('[data-go]').forEach(b => b.addEventListener('click', () => goView(b.dataset.go)));

  // ============ KATEGORI ============
  // >>> Untuk menambah / mengganti nama kategori, cukup ubah baris di bawah ini <<<
  let categories = ['Makanan Berat', 'Makanan Ringan', 'Minuman'];
  let activeFilter = 'Semua';   // kategori yang sedang dipilih di filter

  // ============ DATA MENU (contoh, di memori) ============
  let menus = [
    {id:1, name:'Brownies Original', price:40000, desc:'Cokelat premium, tekstur fudgy dan lembut.', img:IMGS.IMG1, available:true, best:true, category:'Kue'},
    {id:2, name:'Brownies Tiramisu', price:48000, desc:'Perpaduan brownies fudgy dengan sentuhan tiramisu.', img:IMGS.IMG2, available:true, best:false, category:'Kue'},
    {id:3, name:'Brownies Keju', price:45000, desc:'Topping keju melimpah di atas brownies cokelat.', img:IMGS.IMG3, available:false, best:false, category:'Makanan Ringan'},
    {id:4, name:'Brownies Kacang', price:47000, desc:'Renyah kacang almond memenuhi tiap potongan.', img:IMGS.IMG4, available:true, best:true, category:'Makanan Ringan'},
  ];
  let nextId = 5, editingId = null, photoTargetId = null;
  const grid = document.getElementById('menuGrid');
  const filterBar = document.getElementById('filterBar');

  // bar filter kategori (dibuat dari daftar categories)
  function renderFilter(){
    const chips = ['Semua'].concat(categories);
    filterBar.innerHTML = chips.map(c =>
      `<button class="filter-chip ${activeFilter===c?'active':''}" onclick="setFilter('${c.replace(/'/g,"\\'")}')">${c}</button>`
    ).join('');
  }
  function setFilter(cat){ activeFilter = cat; renderFilter(); renderMenu(); }

  function renderMenu(){
    const list = activeFilter==='Semua' ? menus : menus.filter(m => (m.category||'')===activeFilter);
    grid.innerHTML = list.length ? list.map(m => `
      <div class="menu-card ${m.available?'':'out'}">
        <div class="photo-wrap">
          <img src="${m.img}" alt="${m.name}">
          <span class="badge status ${m.available?'ok':'off'}" onclick="toggleStock(${m.id})" title="Klik untuk ubah stok">${m.available?'Tersedia':'Kosong'}</span>
          ${m.best?'<span class="badge best">★ Best Seller</span>':''}
          <div class="change-photo" onclick="changePhoto(${m.id})">
            <svg viewBox="0 0 24 24" fill="none"><path d="M4 8h3l1.5-2h7L17 8h3v11H4V8Z" stroke="currentColor" stroke-width="1.6"/><circle cx="12" cy="13" r="3.2" stroke="currentColor" stroke-width="1.6"/></svg>
            Ganti Foto
          </div>
        </div>
        <div class="card-body">
          <span class="cat-tag">${m.category||'Tanpa kategori'}</span>
          <h3>${m.name}</h3>
          <p class="desc">${m.desc}</p>
          <div class="price">${rupiah(m.price)}</div>
          <div class="card-actions">
            <button class="mini" onclick="editMenu(${m.id})"><svg viewBox="0 0 24 24" fill="none"><path d="M4 20h4L18 10l-4-4L4 16v4Z" stroke="currentColor" stroke-width="1.7" stroke-linejoin="round"/></svg>Edit</button>
            <button class="mini del" onclick="deleteMenu(${m.id})"><svg viewBox="0 0 24 24" fill="none"><path d="M5 7h14M9 7V5h6v2M7 7l1 13h8l1-13" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"/></svg>Hapus</button>
          </div>
        </div>
      </div>`).join('') : '<div class="empty-menu">Belum ada menu di kategori "'+activeFilter+'".</div>';
    document.getElementById('statMenu').textContent = menus.length;
    document.getElementById('menuCount').textContent = list.length + ' menu';
    updateStats();
  }

  // isi angka statistik dari data asli (login & dashboard)
  function updateStats(){
    const set = (id, val) => { const el = document.getElementById(id); if(el) el.textContent = val; };
    set('loginStatMenu', menus.length);
    set('loginStatOrders', orders.length);
    set('statAvailable', menus.filter(m => m.available).length);
  }

  // ubah status stok langsung dari kartu
  function toggleStock(id){ const m=menus.find(x=>x.id===id); if(!m) return; m.available=!m.available; renderMenu(); saveMenus(); toast(m.available?'"'+m.name+'" ditandai Tersedia':'"'+m.name+'" ditandai Kosong'); }

  // ganti foto
  const photoInput = document.getElementById('photoInput');
  function changePhoto(id){ photoTargetId = id; photoInput.click(); }
  photoInput.addEventListener('change', e => {
    const file = e.target.files[0]; if(!file) return;
    const reader = new FileReader();
    reader.onload = () => { const m = menus.find(x => x.id === photoTargetId); if(m){ m.img = reader.result; renderMenu(); toast('Foto menu diperbarui'); } };
    reader.readAsDataURL(file); photoInput.value = '';
  });

  // modal tambah / edit
  const overlay = document.getElementById('overlay');
  const mName = document.getElementById('mName'), mPrice = document.getElementById('mPrice'), mDesc = document.getElementById('mDesc');
  const mCategory = document.getElementById('mCategory');
  function renderCategoryOptions(){ mCategory.innerHTML = categories.map(c => '<option value="'+c+'">'+c+'</option>').join(''); }
  const modalTitle = document.getElementById('modalTitle');
  function openModal(){ overlay.classList.add('show'); mName.focus(); }
  function closeModal(){ overlay.classList.remove('show'); }

  // --- unggah foto di dalam modal ---
  const ICON_SVG = '<svg viewBox="0 0 24 24" fill="none"><path d="M4 8h3l1.5-2h7L17 8h3v11H4V8Z" stroke="currentColor" stroke-width="1.6"/><circle cx="12" cy="13" r="3.2" stroke="currentColor" stroke-width="1.6"/></svg>';
  const mThumb = document.getElementById('mThumb');
  const mPhotoHint = document.getElementById('mPhotoHint');
  const modalPhotoInput = document.getElementById('modalPhotoInput');
  let modalPhoto = null;
  function setThumb(src, hint){
    if(src){ mThumb.innerHTML = '<img src="'+src+'" alt="pratinjau">'; }
    else { mThumb.innerHTML = ICON_SVG; }
    mPhotoHint.textContent = hint;
  }
  document.getElementById('photoDrop').onclick = () => modalPhotoInput.click();
  modalPhotoInput.addEventListener('change', e => {
    const file = e.target.files[0]; if(!file) return;
    const reader = new FileReader();
    reader.onload = () => { modalPhoto = reader.result; mPhotoUrl.value=''; setThumb(modalPhoto, 'Foto dipilih — Klik Jika Ingin Ganti'); };
    reader.readAsDataURL(file); modalPhotoInput.value = '';
  });
  // isi foto lewat URL
  const mPhotoUrl = document.getElementById('mPhotoUrl');
  mPhotoUrl.addEventListener('input', () => {
    const url = mPhotoUrl.value.trim();
    if(url){ modalPhoto = url; setThumb(url, 'Pratinjau dari URL'); }
    else { setThumb(editingId ? (menus.find(x=>x.id===editingId)||{}).img : null, 'Klik Untuk Unggah Foto'); }
  });
  const mAvailable = document.getElementById('mAvailable');
  const mBest = document.getElementById('mBest');
  document.getElementById('addBtn').onclick = () => { editingId=null; modalTitle.textContent='Tambah Menu'; mName.value=''; mPrice.value=''; mDesc.value=''; modalPhoto=null; mPhotoUrl.value=''; setThumb(null,'Ketuk untuk unggah dari perangkat'); mAvailable.checked=true; mBest.checked=false; renderCategoryOptions(); mCategory.value = (activeFilter!=='Semua' ? activeFilter : (categories[0]||'')); openModal(); };
  function editMenu(id){ const m=menus.find(x=>x.id===id); if(!m) return; editingId=id; modalTitle.textContent='Edit Menu'; mName.value=m.name; mPrice.value=m.price; mDesc.value=m.desc; modalPhoto=null; mPhotoUrl.value = (m.img && /^https?:\/\//.test(m.img)) ? m.img : ''; setThumb(m.img,'Foto saat ini — Klik Jika Ingin ganti'); mAvailable.checked=m.available; mBest.checked=m.best; renderCategoryOptions(); mCategory.value = m.category || (categories[0]||''); openModal(); }
  function deleteMenu(id){ const m=menus.find(x=>x.id===id); if(!m) return; askConfirm('Hapus menu "'+m.name+'"?', ()=>{ menus=menus.filter(x=>x.id!==id); renderMenu(); deleteMenuDB(id); toast('Menu dihapus'); }); }
  document.getElementById('cancelBtn').onclick = closeModal;
  overlay.addEventListener('click', e => { if(e.target===overlay) closeModal(); });
  document.getElementById('saveBtn').onclick = () => {
    const name=mName.value.trim(), price=mPrice.value.trim(), desc=mDesc.value.trim();
    if(!name||!price){ toast('Nama dan harga wajib diisi'); return; }
    if(editingId){ const m=menus.find(x=>x.id===editingId); m.name=name; m.price=+price; m.desc=desc||m.desc; if(modalPhoto) m.img=modalPhoto; m.available=mAvailable.checked; m.best=mBest.checked; m.category=mCategory.value; toast('Menu diperbarui'); }
    else { menus.push({id:nextId++, name, price:+price, desc:desc||'Brownies spesial buatan Daily Crave.', img:modalPhoto||IMGS.IMG1, available:mAvailable.checked, best:mBest.checked, category:mCategory.value}); toast('Menu ditambahkan'); }
    closeModal(); renderMenu(); saveMenus();
  };

  // ============ DATA PESANAN (contoh, di memori) ============
  let orders = [
    {id:1043, cust:'Rina', item:'2x Brownies Original', total:80000, status:'Baru'},
    {id:1042, cust:'Andi', item:'1x Brownies Keju', total:45000, status:'Diproses'},
    {id:1041, cust:'Sari', item:'3x Brownies Tiramisu', total:144000, status:'Selesai'},
    {id:1040, cust:'Budi', item:'1x Brownies Kacang', total:47000, status:'Baru'},
  ];
  // beri tanggal + jam contoh pada tiap transaksi (relatif ke hari ini)
  const OFFSET_DAYS = [0, 4, 18, 95];
  const OFFSET_HM = [[9,15],[11,40],[14,5],[16,30]];
  orders.forEach((o,i) => {
    const off = (i < OFFSET_DAYS.length) ? OFFSET_DAYS[i] : i*30;
    const d = new Date(Date.now() - off*86400000);
    const hm = OFFSET_HM[i % OFFSET_HM.length];
    d.setHours(hm[0], hm[1], 0, 0);
    o.date = d;
  });
  function fmtDateTime(d){
    if(!d) return '-';
    return d.toLocaleDateString('id-ID',{day:'2-digit',month:'short'}) + ', ' +
           d.toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'});
  }

  // ===== FILTER PERIODE + TANGGAL (Dashboard & Laporan) =====
  let activePeriod = 'bulan';
  let pickedDate = null; // 'YYYY-MM-DD' bila memilih tanggal tertentu
  const PERIODS = [['hari','Hari Ini'],['bulan','Bulan Ini'],['tahun','Tahun Ini'],['semua','Semua']];
  function inPeriod(d, period){
    const now = new Date();
    if(!d) return true;
    if(period==='hari')  return d.toDateString() === now.toDateString();
    if(period==='bulan') return d.getMonth()===now.getMonth() && d.getFullYear()===now.getFullYear();
    if(period==='tahun') return d.getFullYear()===now.getFullYear();
    return true; // 'semua'
  }
  function sameYMD(d, ymd){
    if(!d || !ymd) return false;
    const [y,m,da] = ymd.split('-').map(Number);
    return d.getFullYear()===y && (d.getMonth()+1)===m && d.getDate()===da;
  }
  function ordersInPeriod(){
    if(pickedDate) return orders.filter(o => sameYMD(o.date, pickedDate));
    return orders.filter(o => inPeriod(o.date, activePeriod));
  }
  function renderPeriodBars(){
    const html = PERIODS.map(([v,l]) => `<button class="filter-chip ${(!pickedDate && activePeriod===v)?'active':''}" onclick="setPeriod('${v}')">${l}</button>`).join('');
    ['dashPeriod','reportPeriod'].forEach(id => { const el=document.getElementById(id); if(el) el.innerHTML = html; });
  }
  function setPeriod(p){
    activePeriod = p; pickedDate = null;
    ['dashDate','reportDate'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    renderPeriodBars(); renderOrders(); renderReport();
  }
  function onPickDate(val){
    pickedDate = val || null;
    ['dashDate','reportDate'].forEach(id => { const el=document.getElementById(id); if(el) el.value = pickedDate || ''; });
    renderPeriodBars(); renderOrders(); renderReport();
  }

  const NEXT = {Baru:'Diproses', Diproses:'Selesai'};
  const NEXT_LABEL = {Baru:'Proses', Diproses:'Selesaikan'};

  function rowHTML(o, compact){
    const next = NEXT[o.status];
    const actionBtn = next
      ? `<button class="obtn ${next==='Selesai'?'done':'go'}" onclick="advanceOrder(${o.id})">${NEXT_LABEL[o.status]}</button>`
      : `<button class="obtn" disabled>Selesai ✓</button>`;
    if(compact){
      return `<tr><td class="o-id">#${o.id}</td><td>${o.cust}<div class="o-subtime">${fmtDateTime(o.date)}</div></td><td class="o-total">${rupiah(o.total)}</td><td><span class="pill ${o.status}">${o.status}</span></td></tr>`;
    }
    return `<tr>
      <td class="o-id">#${o.id}</td>
      <td class="o-time">${fmtDateTime(o.date)}</td>
      <td>${o.cust}${o.alamat ? '<div class="o-extra">📍 '+o.alamat+'</div>' : ''}</td>
      <td>${o.item}${o.note ? '<div class="o-extra note">📝 '+o.note+'</div>' : ''}</td>
      <td class="o-total">${rupiah(o.total)}</td>
      <td><span class="pill ${o.status}">${o.status}</span></td>
      <td><div class="o-actions">${actionBtn}<button class="obtn" onclick="deleteOrder(${o.id})">Hapus</button></div></td>
    </tr>`;
  }
  function renderOrders(){
    const full = document.getElementById('ordersFull');
    const recent = document.getElementById('ordersRecent');
    full.innerHTML = orders.length ? orders.map(o=>rowHTML(o,false)).join('') : `<tr><td colspan="7" class="empty">Belum ada pesanan.</td></tr>`;
    const periodOrders = ordersInPeriod().slice().sort((a,b)=>b.date-a.date);
    recent.innerHTML = periodOrders.length ? periodOrders.slice(0,6).map(o=>rowHTML(o,true)).join('') : `<tr><td colspan="4" class="empty">Belum ada pesanan pada periode ini.</td></tr>`;
    const active = orders.filter(o=>o.status!=='Selesai').length;
    document.getElementById('statOrders').textContent = active;
    document.getElementById('navPesananCount').textContent = active;
    if (typeof renderReport === 'function') renderReport();
    if (typeof updateStats === 'function') updateStats();
  }
  function advanceOrder(id){ const o=orders.find(x=>x.id===id); if(o&&NEXT[o.status]){ o.status=NEXT[o.status]; renderOrders(); saveOrderStatus(o); toast('Pesanan #'+id+' → '+o.status); } }
  function deleteOrder(id){ askConfirm('Hapus pesanan #'+id+'?', ()=>{ orders=orders.filter(x=>x.id!==id); renderOrders(); deleteOrderDB(id); toast('Pesanan dihapus'); }); }

  // ============ KONFIRMASI HAPUS (buatan sendiri) ============
  const confirmOverlay = document.getElementById('confirmOverlay');
  const confirmMsg = document.getElementById('confirmMsg');
  let confirmCb = null;
  function askConfirm(msg, cb){ confirmMsg.textContent = msg; confirmCb = cb; confirmOverlay.classList.add('show'); }
  function closeConfirm(){ confirmOverlay.classList.remove('show'); confirmCb = null; }
  document.getElementById('confirmNo').onclick = closeConfirm;
  document.getElementById('confirmYes').onclick = () => { if(confirmCb) confirmCb(); closeConfirm(); };
  confirmOverlay.addEventListener('click', e => { if(e.target === confirmOverlay) closeConfirm(); });

  // ============ TOAST ============
  let toastTimer;
  function toast(msg){ const t=document.getElementById('toast'); t.textContent=msg; t.classList.add('show'); clearTimeout(toastTimer); toastTimer=setTimeout(()=>t.classList.remove('show'),2200); }

  // ============ LAPORAN PENJUALAN (dihitung dari transaksi/pesanan) ============
  // memisah teks "2x Brownies Original" menjadi jumlah & nama menu
  function parseItem(str){
    const m = /^(\d+)\s*x\s*(.+)$/i.exec((str||'').trim());
    return m ? { qty: parseInt(m[1],10), name: m[2].trim() } : { qty: 1, name: (str||'').trim() };
  }
  function renderReport(){
    const src = (typeof ordersInPeriod === 'function') ? ordersInPeriod() : orders;
    const totalRev = src.reduce((s,o)=>s+o.total,0);
    const totalTx  = src.length;
    const avg = totalTx ? Math.round(totalRev/totalTx) : 0;

    // gabungkan penjualan per menu dari transaksi pada periode ini
    const perMenu = {};
    src.forEach(o => {
      const it = parseItem(o.item);
      if(!perMenu[it.name]) perMenu[it.name] = { qty:0, revenue:0 };
      perMenu[it.name].qty += it.qty;
      perMenu[it.name].revenue += o.total;
    });
    const rows = Object.keys(perMenu).map(name => ({ name, qty:perMenu[name].qty, revenue:perMenu[name].revenue }))
                       .sort((a,b)=>b.revenue-a.revenue);
    const best = rows.slice().sort((a,b)=>b.qty-a.qty)[0];

    document.getElementById('repTotal').textContent = rupiah(totalRev);
    document.getElementById('repQty').textContent   = totalTx + ' transaksi';
    document.getElementById('repBest').textContent  = best ? best.name : '-';
    document.getElementById('repAvg').textContent   = rupiah(avg);

    const max = Math.max(1, ...rows.map(r=>r.revenue));
    document.getElementById('reportBars').innerHTML = rows.length ? rows.map(r => `
      <div class="bar-row">
        <div class="bar-name">${r.name}</div>
        <div class="bar-track"><div class="bar-fill" style="width:${(r.revenue/max*100).toFixed(1)}%"></div></div>
        <div class="bar-val">${rupiah(r.revenue)}</div>
      </div>`).join('') : '<div class="empty-menu">Belum ada transaksi.</div>';

    // daftar transaksi (bisa dicek satu per satu)
    document.getElementById('reportTable').innerHTML = src.length ? src.slice().sort((a,b)=>b.date-a.date).map(o => `
      <tr>
        <td class="o-id">#${o.id}</td>
        <td class="o-time">${fmtDateTime(o.date)}</td>
        <td>${o.cust}</td>
        <td>${o.item}</td>
        <td class="o-total">${rupiah(o.total)}</td>
        <td><span class="pill ${o.status}">${o.status}</span></td>
      </tr>`).join('') : '<tr><td colspan="6" class="empty">Belum ada transaksi pada periode ini.</td></tr>';
  }

